/// Ask the `target` sidebar pane to focus itself (todo #110). Sent as a
/// `panopt:focus-pane` pipe narrowed by `--plugin-configuration
/// mode=<slug>` so it reaches only that instance, which focuses its own
/// pane (and no-ops while a popup is up). We go through `zellij action
/// pipe` rather than the in-process `pipe_message_to_plugin` for the same
/// reason the cockpit keybinds do: that API launches a fresh instance when
/// no exact `(url, config)` match is found, whereas the CLI's
/// configuration narrowing only ever reaches a *running* instance. Unlike
/// the keybind path, a plugin-issued `run_command` spawns no transient
/// focus-stealing pane.
fn request_focus_pane(&self, target: Mode) {
    run_command(
        &[
            "zellij",
            "action",
            "pipe",
            "--name",
            "panopt:focus-pane",
            "--plugin-configuration",
            &format!("mode={}", target.slug()),
        ],
        BTreeMap::new(),
    );
}

