/// `Alt-<1..5>` focuses a sidebar pane, lazygit-style (todo #110):
/// `1`=Todos, `2`=Agents, `3`=Terminals, `4`=Commands, `5`=Scratchpads. These
/// fire on auto-locked content panes; the same gesture on a sidebar plugin
/// pane (Normal mode) is handled inside the plugin's `handle_key`. Both emit a
/// `panopt:focus-pane` pipe narrowed to the target instance's `mode`, which
/// focuses its own pane - and no-ops while a floating popup (search / gate
/// dialog) holds focus, so the gesture never yanks the user out of a popup.
/// Built rather than `const`-ed because the mode slug varies per digit; see
/// [`NEW_PANE_BIND_FROM`] for why the cockpit pipes through `zellij action
/// pipe` rather than `MessagePlugin`.
fn focus_pane_binds() -> String {
    [
        (1, "todos"),
        (2, "agents"),
        (3, "terminals"),
        (4, "commands"),
        (5, "scratchpads"),
    ]
    .iter()
    .map(|(digit, mode)| {
        format!(
            r#"bind "Alt {digit}" {{ Run "zellij" "action" "pipe" "--name" "panopt:focus-pane" "--plugin-configuration" "mode={mode}" {{ close_on_exit true; }}; }}"#
        )
    })
    .collect::<Vec<_>>()
    .join("\n        ")
}

