/// Built rather than `const`-ed because the mode slug varies per digit; see
/// [`NEW_PANE_BIND_FROM`] for why the cockpit pipes through `zellij action
/// pipe` rather than `MessagePlugin`.
fn focus_pane_binds() -> String {
    [
        (1, "todos"),
        (2, "agents"),
        (3, "terminals"),
        (4, "commands"),
        (5, "scratchpads"),
    ]
    .iter()
    .map(|(digit, mode)| {
        format!(
            r#"bind "Alt {digit}" {{ Run "zellij" "action" "pipe" "--name" "panopt:focus-pane" "--plugin-configuration" "mode={mode}" {{ close_on_exit true; }}; }}"#
        )
    })
    .collect::<Vec<_>>()
    .join("\n        ")
}

